// Icon: material-symbols:cloud-download
// Slug: Patches elements into the DOM.
// Description: Patches elements into the DOM.

import { watcher } from '@engine'
import type { WatcherArgsValue, WatcherContext } from '@engine/types'
import { isHTMLOrSVG } from '@utils/dom'
import { aliasify } from '@utils/text'
import { supportsViewTransitions } from '@utils/view-transitions'

const isValidType = <T extends readonly string[]>(
  arr: T,
  value: string,
): value is T[number] => (arr as readonly string[]).includes(value)

const PATCH_MODES = [
  'remove',
  'outer',
  'inner',
  'replace',
  'prepend',
  'append',
  'before',
  'after',
] as const
type PatchElementsMode = (typeof PATCH_MODES)[number]

const NAMESPACES = ['html', 'svg', 'mathml'] as const
type Namespace = (typeof NAMESPACES)[number]

type PatchElementsArgs = {
  selector: string
  mode: PatchElementsMode
  namespace: Namespace
  useViewTransition: boolean
  elements: WatcherArgsValue
}

watcher({
  name: 'datastar-patch-elements',
  apply(ctx, args) {
    const selector = typeof args.selector === 'string' ? args.selector : ''
    const mode = typeof args.mode === 'string' ? args.mode : 'outer'
    const namespace =
      typeof args.namespace === 'string' ? args.namespace : 'html'
    const useViewTransitionRaw =
      typeof args.useViewTransition === 'string' ? args.useViewTransition : ''
    const elements = args.elements

    if (!isValidType(PATCH_MODES, mode)) {
      throw ctx.error('PatchElementsInvalidMode', { mode })
    }

    if (!selector && mode !== 'outer' && mode !== 'replace') {
      throw ctx.error('PatchElementsExpectedSelector')
    }

    if (!isValidType(NAMESPACES, namespace)) {
      throw ctx.error('PatchElementsInvalidNamespace', { namespace })
    }

    const args2: PatchElementsArgs = {
      selector,
      mode,
      namespace,
      useViewTransition: useViewTransitionRaw.trim() === 'true',
      elements,
    }

    if (supportsViewTransitions && args2.useViewTransition) {
      document.startViewTransition(() => onPatchElements(ctx, args2))
    } else {
      onPatchElements(ctx, args2)
    }
  },
})

const onPatchElements = (
  { error }: WatcherContext,
  { selector, mode, namespace, elements }: PatchElementsArgs,
) => {
  let newContent = document.createDocumentFragment()
  const consume = typeof elements !== 'string' && !!elements

  if (typeof elements === 'string') {
    const elementsWithSvgsRemoved = elements.replace(
      /<svg(\s[^>]*>|>)([\s\S]*?)<\/svg>/gim,
      '',
    )
    const hasHtml = /<\/html>/.test(elementsWithSvgsRemoved)
    const hasHead = /<\/head>/.test(elementsWithSvgsRemoved)
    const hasBody = /<\/body>/.test(elementsWithSvgsRemoved)

    const wrapperTag =
      namespace === 'svg' ? 'svg' : namespace === 'mathml' ? 'math' : ''
    const wrappedEls = wrapperTag
      ? `<${wrapperTag}>${elements}</${wrapperTag}>`
      : elements

    const newDocument = new DOMParser().parseFromString(
      hasHtml || hasHead || hasBody
        ? elements
        : `<body><template>${wrappedEls}</template></body>`,
      'text/html',
    )

    if (hasHtml) {
      newContent.appendChild(newDocument.documentElement)
    } else if (hasHead && hasBody) {
      newContent.appendChild(newDocument.head)
      newContent.appendChild(newDocument.body)
    } else if (hasHead) {
      newContent.appendChild(newDocument.head)
    } else if (hasBody) {
      newContent.appendChild(newDocument.body)
    } else if (wrapperTag) {
      const wrapperEl = newDocument
        .querySelector('template')!
        .content.querySelector(wrapperTag)!
      for (const child of wrapperEl.childNodes) {
        newContent.appendChild(child)
      }
    } else {
      newContent = newDocument.querySelector('template')!.content
    }
  } else if (elements) {
    if (elements instanceof DocumentFragment) {
      newContent = elements
    } else if (elements instanceof Element) {
      newContent.appendChild(elements)
    }
  }

  if (!selector && (mode === 'outer' || mode === 'replace')) {
    const children = Array.from(newContent.children)
    for (const child of children) {
      let target: Element
      if (child instanceof HTMLHtmlElement) {
        target = document.documentElement
      } else if (child instanceof HTMLBodyElement) {
        target = document.body
      } else if (child instanceof HTMLHeadElement) {
        target = document.head
      } else {
        target = document.getElementById(child.id)!
        if (!target) {
          console.warn(error('PatchElementsNoTargetsFound'), {
            element: { id: child.id },
          })
          continue
        }
      }

      applyToTargets(mode as PatchElementsMode, child, [target], consume)
    }
  } else {
    const targets = document.querySelectorAll(selector)
    if (!targets.length) {
      console.warn(error('PatchElementsNoTargetsFound'), { selector })
      return
    }

    const targetList = consume && mode !== 'remove' ? [targets[0]!] : targets
    applyToTargets(mode as PatchElementsMode, newContent, targetList, consume)
  }
}

const scripts = new WeakSet<HTMLScriptElement>()
for (const script of document.querySelectorAll('script')) {
  scripts.add(script)
}

const execute = (target: Element): void => {
  const elScripts =
    target instanceof HTMLScriptElement
      ? [target]
      : target.querySelectorAll('script')
  for (const old of elScripts) {
    if (!scripts.has(old)) {
      const script = document.createElement('script')
      for (const { name, value } of old.attributes) {
        script.setAttribute(name, value)
      }
      script.text = old.text
      old.replaceWith(script)
      scripts.add(script)
    }
  }
}

const applyPatchMode = (
  targets: Iterable<Element>,
  element: DocumentFragment | Element,
  action: string,
  consume: boolean,
) => {
  let used = false
  for (const target of targets) {
    if (consume && used) {
      break
    }
    const nextNode = consume ? element : (element.cloneNode(true) as Element)
    execute(nextNode as Element)
    // @ts-expect-error - calling dynamic method path on DOM element
    target[action](nextNode)
    used = true
  }
}

const applyToTargets = (
  mode: PatchElementsMode,
  element: DocumentFragment | Element,
  targets: Iterable<Element>,
  consume: boolean,
) => {
  switch (mode) {
    case 'remove':
      for (const target of targets) {
        target.remove()
      }
      break
    case 'outer':
    case 'inner':
      {
        let used = false
        for (const target of targets) {
          if (consume && used) {
            break
          }
          const nextNode = consume
            ? element
            : (element.cloneNode(true) as Element)
          morph(target, nextNode, mode)
          execute(target)
          const scopeHost = target.closest('[data-scope-children]')
          if (scopeHost) {
            scopeHost.dispatchEvent(
              new CustomEvent('datastar:scope-children', { bubbles: false }),
            )
          }
          used = true
        }
      }
      break
    case 'replace':
      applyPatchMode(targets, element, 'replaceWith', consume)
      break
    case 'prepend':
    case 'append':
    case 'before':
    case 'after':
      applyPatchMode(targets, element, mode, consume)
  }
}

const ctxIdMap = new Map<Node, Set<string>>()
const ctxPersistentIds = new Set<string>()
const oldIdTagNameMap = new Map<string, string>()
const duplicateIds = new Set<string>()
const ctxPantry = document.createElement('div')
ctxPantry.hidden = true

const aliasedIgnoreMorph = aliasify('ignore-morph')
const aliasedIgnoreMorphAttr = `[${aliasedIgnoreMorph}]`
const morph = (
  oldElt: Element | ShadowRoot,
  newContent: DocumentFragment | Element,
  mode: 'outer' | 'inner' = 'outer',
): void => {
  if (
    (isHTMLOrSVG(oldElt) &&
      isHTMLOrSVG(newContent) &&
      oldElt.hasAttribute(aliasedIgnoreMorph) &&
      newContent.hasAttribute(aliasedIgnoreMorph)) ||
    oldElt.parentElement?.closest(aliasedIgnoreMorphAttr)
  ) {
    return
  }

  const normalizedElt = document.createElement('div')
  normalizedElt.append(newContent)
  document.body.insertAdjacentElement('afterend', ctxPantry)

  // Computes the set of IDs that persist between the two contents excluding duplicates
  const oldIdElements = oldElt.querySelectorAll('[id]')
  for (const { id, tagName } of oldIdElements) {
    if (oldIdTagNameMap.has(id)) {
      duplicateIds.add(id)
    } else {
      oldIdTagNameMap.set(id, tagName)
    }
  }
  if (oldElt instanceof Element && oldElt.id) {
    if (oldIdTagNameMap.has(oldElt.id)) {
      duplicateIds.add(oldElt.id)
    } else {
      oldIdTagNameMap.set(oldElt.id, oldElt.tagName)
    }
  }

  ctxPersistentIds.clear()
  const newIdElements = normalizedElt.querySelectorAll('[id]')
  for (const { id, tagName } of newIdElements) {
    if (ctxPersistentIds.has(id)) {
      duplicateIds.add(id)
    } else if (oldIdTagNameMap.get(id) === tagName) {
      ctxPersistentIds.add(id)
    }
  }

  for (const id of duplicateIds) {
    ctxPersistentIds.delete(id)
  }

  oldIdTagNameMap.clear()
  duplicateIds.clear()
  ctxIdMap.clear()

  const parent = mode === 'outer' ? oldElt.parentElement! : oldElt
  populateIdMapWithTree(parent, oldIdElements)
  populateIdMapWithTree(normalizedElt, newIdElements)

  morphChildren(
    parent,
    normalizedElt,
    mode === 'outer' ? oldElt : null,
    oldElt.nextSibling,
  )

  ctxPantry.remove()
}

// This is the core algorithm for matching up children.
// The idea is to use ID sets to try to match up nodes as faithfully as possible.
// We greedily match, which allows us to keep the algorithm fast,
// but by using ID sets, we are able to better match up with content deeper in the DOM.
const morphChildren = (
  oldParent: Element | ShadowRoot, // the old content that we are merging the new content into
  newParent: Element, // the parent element of the new content
  insertionPoint: Node | null = null, // the point in the DOM we start morphing at (defaults to first child)
  endPoint: Node | null = null, // the point in the DOM we stop morphing at (defaults to after last child)
): void => {
  // normalize
  if (
    oldParent instanceof HTMLTemplateElement &&
    newParent instanceof HTMLTemplateElement
  ) {
    // we can pretend the DocumentElement is an Element
    oldParent = oldParent.content as unknown as Element
    newParent = newParent.content as unknown as Element
  }
  insertionPoint ??= oldParent.firstChild

  // run through all the new content
  for (const newChild of newParent.childNodes) {
    // once we reach the end of the old parent content skip to the end and insert the rest
    if (insertionPoint && insertionPoint !== endPoint) {
      const bestMatch = findBestMatch(newChild, insertionPoint, endPoint)
      if (bestMatch) {
        // if the node to morph is not at the insertion point then remove/move up to it
        if (bestMatch !== insertionPoint) {
          let cursor: Node | null = insertionPoint
          // Remove nodes between the start and end nodes
          while (cursor && cursor !== bestMatch) {
            const tempNode = cursor
            cursor = cursor.nextSibling
            removeNode(tempNode)
          }
        }
        morphNode(bestMatch, newChild)
        insertionPoint = bestMatch.nextSibling
        continue
      }
    }

    // if the matching node is elsewhere in the original content
    if (newChild instanceof Element && ctxPersistentIds.has(newChild.id)) {
      // move it and all its children here and morph, will always be found
      // Search for an element by ID within the document and pantry, and move it using moveBefore.
      const movedChild = document.getElementById(newChild.id) as Element

      // Removes an element from its ancestors' ID maps.
      // This is needed when an element is moved from the "future" via `moveBeforeId`.
      // Otherwise, its erstwhile ancestors could be mistakenly moved to the pantry rather than being deleted,
      // preventing their removal hooks from being called.
      let current = movedChild
      while ((current = current.parentNode as Element)) {
        const idSet = ctxIdMap.get(current)
        if (idSet) {
          idSet.delete(newChild.id)
          if (!idSet.size) {
            ctxIdMap.delete(current)
          }
        }
      }

      moveBefore(oldParent, movedChild, insertionPoint)
      morphNode(movedChild, newChild)
      insertionPoint = movedChild.nextSibling
      continue
    }

    // This performs the action of inserting a new node while handling situations where the node contains
    // elements with persistent IDs and possible state info we can still preserve by moving in and then morphing
    if (ctxIdMap.has(newChild)) {
      // node has children with IDs with possible state so create a dummy elt of same type and apply full morph algorithm
      const namespaceURI = (newChild as Element).namespaceURI
      const tagName = (newChild as Element).tagName
      const newEmptyChild =
        namespaceURI && namespaceURI !== 'http://www.w3.org/1999/xhtml'
          ? document.createElementNS(namespaceURI, tagName)
          : document.createElement(tagName)
      oldParent.insertBefore(newEmptyChild, insertionPoint)
      morphNode(newEmptyChild, newChild)
      insertionPoint = newEmptyChild.nextSibling
    } else {
      // optimization: no id state to preserve so we can just insert a clone of the newChild and its descendants
      const newClonedChild = document.importNode(newChild, true) // importNode to not mutate newParent
      oldParent.insertBefore(newClonedChild, insertionPoint)
      insertionPoint = newClonedChild.nextSibling
    }
  }

  // remove any remaining old nodes that didn't match up with new content
  while (insertionPoint && insertionPoint !== endPoint) {
    const tempNode = insertionPoint
    insertionPoint = insertionPoint.nextSibling
    removeNode(tempNode)
  }
}

// Scans forward from the startPoint to the endPoint looking for a match for the node.
// It looks for an id set match first, then a soft match.
// We abort soft matching if we find two future soft matches, to reduce churn.
const findBestMatch = (
  node: Node,
  startPoint: Node | null,
  endPoint: Node | null,
): Node | null => {
  let bestMatch: Node | null | undefined = null
  let nextSibling = node.nextSibling
  let siblingSoftMatchCount = 0
  let displaceMatchCount = 0

  // Max ID matches we are willing to displace in our search
  const nodeMatchCount = ctxIdMap.get(node)?.size || 0

  let cursor = startPoint
  while (cursor && cursor !== endPoint) {
    // soft matching is a prerequisite for id set matching
    if (isSoftMatch(cursor, node)) {
      let isIdSetMatch = false
      const oldSet = ctxIdMap.get(cursor)
      const newSet = ctxIdMap.get(node)

      if (newSet && oldSet) {
        for (const id of oldSet) {
          // a potential match is an id in the new and old nodes that
          // has not already been merged into the DOM
          // But the newNode content we call this on has not been
          // merged yet and we don't allow duplicate IDs so it is simple
          if (newSet.has(id)) {
            isIdSetMatch = true
            break
          }
        }
      }

      if (isIdSetMatch) {
        return cursor // found an id set match, we're done!
      }

      // we haven’t yet saved a soft match fallback
      // the current soft match will hard match something else in the future, leave it
      if (!bestMatch && !ctxIdMap.has(cursor)) {
        // optimization: if node can't id set match, we can just return the soft match immediately
        if (!nodeMatchCount) {
          return cursor
        }
        // save this as the fallback if we get through the loop without finding a hard match
        bestMatch = cursor
      }
    }

    // check for IDs we may be displaced when matching
    displaceMatchCount += ctxIdMap.get(cursor)?.size || 0
    if (displaceMatchCount > nodeMatchCount) {
      // if we are going to displace more IDs than the node contains then
      // we do not have a good candidate for an ID match, so return
      break
    }

    if (bestMatch === null && nextSibling && isSoftMatch(cursor, nextSibling)) {
      // The next new node has a soft match with this node, so
      // increment the count of future soft matches
      siblingSoftMatchCount++
      nextSibling = nextSibling.nextSibling

      // If there are two future soft matches, block soft matching for this node to allow
      // future siblings to soft match. This is to reduce churn in the DOM when an element
      // is prepended.
      if (siblingSoftMatchCount >= 2) {
        bestMatch = undefined
      }
    }

    cursor = cursor.nextSibling
  }

  return bestMatch || null
}

// ok to cast: if one is not element, `id` and `tagName` will be null and we'll just compare that.
const isSoftMatch = (oldNode: Node, newNode: Node): boolean =>
  oldNode.nodeType === newNode.nodeType &&
  (oldNode as Element).tagName === (newNode as Element).tagName &&
  // If oldElt has an `id` with possible state and it doesn’t match newElt.id then avoid morphing.
  // We'll still match an anonymous node with an IDed newElt, though, because if it got this far,
  // its not persistent, and new nodes can't have any hidden state.
  (!(oldNode as Element).id ||
    (oldNode as Element).id === (newNode as Element).id)

// Gets rid of an unwanted DOM node; strategy depends on nature of its reuse:
// - Persistent nodes will be moved to the pantry for later reuse
// - Other nodes will have their hooks called, and then are removed
const removeNode = (node: Node): void => {
  // are we going to id set match this later?
  ctxIdMap.has(node)
    ? // skip callbacks and move to pantry
      moveBefore(ctxPantry, node, null)
    : // remove for realsies
      node.parentNode?.removeChild(node)
}

// Moves an element before another element within the same parent.
// Uses the proposed `moveBefore` API if available (and working), otherwise falls back to `insertBefore`.
// This is essentially a forward-compat wrapper.
const moveBefore: (parentNode: Node, node: Node, after: Node | null) => void =
  // @ts-expect-error
  removeNode.call.bind(ctxPantry.moveBefore ?? ctxPantry.insertBefore)

const aliasedPreserveAttr = aliasify('preserve-attr')

// syncs the oldNode to the newNode, copying over all attributes and
// inner element state from the newNode to the oldNode
const morphNode = (
  oldNode: Node, // root node to merge content into
  newNode: Node, // new content to merge
): Node => {
  const type = newNode.nodeType

  // if is an element type, sync the attributes from the
  // new node into the new node
  if (type === 1 /* element type */) {
    const oldElt = oldNode as Element
    const newElt = newNode as Element
    const shouldScopeChildren = oldElt.hasAttribute('data-scope-children')
    if (
      oldElt.hasAttribute(aliasedIgnoreMorph) &&
      newElt.hasAttribute(aliasedIgnoreMorph)
    ) {
      return oldNode
    }

    // The following logic for handling inputs, textareas, and options is finnicky.
    // Only change with extreme caution and lots of testing!
    // --
    //  many bothans died to bring us this information:
    //  https://github.com/patrick-steele-idem/morphdom/blob/master/src/specialElHandlers.js
    //  https://github.com/choojs/nanomorph/blob/master/lib/morph.js#L113
    // --

    const preserveAttrs = (
      (newNode as HTMLElement).getAttribute(aliasedPreserveAttr) ?? ''
    ).split(' ')

    const updateElementProp = (
      oldElt: Element,
      newElt: Element,
      name: string,
    ): boolean => {
      const newEltHasAttr = newElt.hasAttribute(name)
      if (
        oldElt.hasAttribute(name) !== newEltHasAttr &&
        !preserveAttrs.includes(name)
      ) {
        // @ts-expect-error - setting dynamic property for native DOM properties
        oldElt[name] = newEltHasAttr
        return true
      }
      return false
    }

    let shouldDispatchChangeEvent = false
    if (
      oldElt instanceof HTMLInputElement &&
      newElt instanceof HTMLInputElement &&
      newElt.type !== 'file'
    ) {
      // Modify the value only if the new element’s value attribute is different from the old element’s value attribute
      const newValue = newElt.getAttribute('value')
      if (
        oldElt.getAttribute('value') !== newValue &&
        !preserveAttrs.includes('value')
      ) {
        oldElt.value = newValue ?? ''
        shouldDispatchChangeEvent = true
      }
      // Update checked and disabled properties
      shouldDispatchChangeEvent =
        updateElementProp(oldElt, newElt, 'checked') ||
        shouldDispatchChangeEvent
      updateElementProp(oldElt, newElt, 'disabled')
    } else if (
      oldElt instanceof HTMLTextAreaElement &&
      newElt instanceof HTMLTextAreaElement
    ) {
      // Modify the value only if the new element’s value is different from the old element’s default value
      const newValue = newElt.value
      if (oldElt.defaultValue !== newValue) {
        oldElt.value = newValue
        shouldDispatchChangeEvent = true
      }
    } else if (
      oldElt instanceof HTMLOptionElement &&
      newElt instanceof HTMLOptionElement
    ) {
      shouldDispatchChangeEvent =
        updateElementProp(oldElt, newElt, 'selected') ||
        shouldDispatchChangeEvent
    }

    for (const { name, value } of newElt.attributes) {
      if (
        oldElt.getAttribute(name) !== value &&
        !preserveAttrs.includes(name)
      ) {
        oldElt.setAttribute(name, value)
      }
    }

    // Create a static copy, so we can iterate forward safely as we remove attributes
    for (const { name } of Array.from(oldElt.attributes)) {
      if (!newElt.hasAttribute(name) && !preserveAttrs.includes(name)) {
        oldElt.removeAttribute(name)
      }
    }

    if (shouldDispatchChangeEvent) {
      const dispatchElt =
        oldElt instanceof HTMLOptionElement ? oldElt.closest('select') : oldElt
      dispatchElt?.dispatchEvent(new Event('change', { bubbles: true }))
    }

    // Preserve the scope marker even if the incoming markup doesn't carry it.
    if (shouldScopeChildren && !oldElt.hasAttribute('data-scope-children')) {
      oldElt.setAttribute('data-scope-children', '')
    }

    if (
      oldElt instanceof HTMLTemplateElement &&
      newElt instanceof HTMLTemplateElement
    ) {
      oldElt.innerHTML = newElt.innerHTML
    } else if (!oldElt.isEqualNode(newElt)) {
      morphChildren(oldElt, newElt)
    }

    if (shouldScopeChildren) {
      oldElt.dispatchEvent(
        new CustomEvent('datastar:scope-children', { bubbles: false }),
      )
    }
  }

  if (type === 8 /* comment */ || type === 3 /* text */) {
    if (oldNode.nodeValue !== newNode.nodeValue) {
      oldNode.nodeValue = newNode.nodeValue
    }
  }

  return oldNode
}

// A bottom-up algorithm that populates a map of Element -> IdSet.
// The ID set for a given element is the set of all IDs contained within its subtree.
// As an optimization, we filter these IDs through the given list of persistent IDs,
// because we don't need to bother considering IDed elements that won't be in the new content.
const populateIdMapWithTree = (
  root: Element | ShadowRoot | null,
  elements: Iterable<Element>,
): void => {
  for (const elt of elements) {
    if (ctxPersistentIds.has(elt.id)) {
      let current: Element | null = elt
      // walk up the parent hierarchy of that element, adding the ID of element to the parent's ID set
      while (current && current !== root) {
        let idSet = ctxIdMap.get(current)
        // if the ID set doesn’t exist, create it and insert it in the map
        if (!idSet) {
          idSet = new Set()
          ctxIdMap.set(current, idSet)
        }
        idSet.add(elt.id)
        current = current.parentElement
      }
    }
  }
}

// Icon: material-symbols:settings-input-antenna
// Slug: Patches signals.
// Description: Patches signals.

import { watcher } from '@engine'
import { mergePatch } from '@engine/signals'
import { jsStrToObject } from '@utils/text'

watcher({
  name: 'datastar-patch-signals',
  apply({ error }, { signals, onlyIfMissing }) {
    if (typeof signals !== 'string') {
      throw error('PatchSignalsExpectedSignals')
    }

    const ifMissing =
      typeof onlyIfMissing === 'string' && onlyIfMissing.trim() === 'true'
    mergePatch(jsStrToObject(signals), { ifMissing })
  },
})

// Icon: mdi:clipboard
// Slug: Copy text to the clipboard
// Description: This action copies text to the clipboard using the Clipboard API.

import { action } from '@engine'

action({
  name: 'clipboard',
  apply: ({ error }, text: string, isBase64 = false) => {
    if (!navigator.clipboard) {
      throw error('ClipboardNotAvailable')
    }

    navigator.clipboard.writeText(isBase64 ? atob(text) : text)
  },
})

// Icon: material-symbols:fit-screen-outline
// Slug: Clamp a value to a new range
// Description: This action clamps a value to a new range. The value is first scaled to the new range, then clamped to the new range. This is useful for scaling a value to a new range, then clamping it to that range.

import { action } from '@engine'
import { inverseLerp, lerp } from '@utils/math'

action({
  name: 'fit',
  apply: (
    _,
    v: number,
    oldMin: number,
    oldMax: number,
    newMin: number,
    newMax: number,
    shouldClamp = false,
    shouldRound = false,
  ) => {
    const t = inverseLerp(oldMin, oldMax, v, shouldClamp)
    let fitted = lerp(newMin, newMax, t, shouldClamp)
    if (shouldRound) fitted = Math.round(fitted)
    return fitted
  },
})

// Icon: material-symbols:language
// Slug: Internationalizes a value.
// Description: Internationalizes a value.

import { action } from '@engine'

action({
  name: 'intl',
  apply(
    { error },
    type: string,
    value: any,
    options: Record<string, any>,
    locales?: string | string[],
  ) {
    const locale = locales || navigator.language || 'en-US'
    switch (type) {
      case 'datetime': {
        const date = value instanceof Date ? value : new Date(value)
        if (Number.isNaN(date.getTime())) {
          throw error('IntlInvalidDate', { value })
        }
        return new Intl.DateTimeFormat(
          locale,
          options as Intl.DateTimeFormatOptions,
        ).format(date)
      }
      case 'number':
        return new Intl.NumberFormat(locale, options).format(
          typeof value === 'number' ? value : parseFloat(value),
        )
      case 'pluralRules':
        return new Intl.PluralRules(
          locale,
          options as Intl.PluralRulesOptions,
        ).select(Number(value))
      case 'relativeTime': {
        const unit = (options as any).unit?.[0] ?? 'day'
        return new Intl.RelativeTimeFormat(
          locale,
          options as Intl.RelativeTimeFormatOptions,
        ).format(Number(value), unit as Intl.RelativeTimeFormatUnit)
      }
      case 'list':
        return new Intl.ListFormat(
          locale,
          options as Intl.ListFormatOptions,
        ).format(Array.isArray(value) ? value.map(String) : [String(value)])
      case 'displayNames': {
        const displayType = (options as any).type || 'language'
        const opts = { ...options, type: displayType } as Record<string, any>
        return new Intl.DisplayNames(
          locale,
          opts as Intl.DisplayNamesOptions,
        ).of(String(value))
      }
      default:
        throw error('IntlTypeNotSupported', { type })
    }
  },
})

// Icon: material-symbols:animated-images
// Slug: Animates element attributes over time.
// Description: Allows you to animate element attributes over time. Animated attributes are updated reactively whenever signals used in the expression change.

import { attribute } from '@engine'
import { effect } from '@engine/signals'
import { inverseLerp, lerp } from '@utils/math'
import { tagFirst, tagToMs } from '@utils/tags'

attribute({
  name: 'animate',
  requirement: {
    value: 'must',
  },
  returnsValue: true,
  apply({ el, key, mods, rx }) {
    let duration = 1000
    const durationArgs = mods.get('duration')
    if (durationArgs) {
      duration = tagToMs(durationArgs)
    }
    const easingName = tagFirst(mods.get('ease'), 'linear')
    const easing = Easing[easingName]
    if (!easing) {
      throw new Error(
        `Invalid easing function: ${easingName}. Available easing functions: ${Object.keys(Easing).join(', ')}`,
      )
    }
    let delay = 0
    const delayArgs = mods.get('delay')
    if (delayArgs) {
      delay = tagToMs(delayArgs)
    }
    let animId = -1
    const cancelAnimation = () => {
      if (animId === -1) return
      cancelAnimationFrame(animId)
      animId = -1
    }
    const startAttributeAnimation = (key: string, targetValueRaw: string) => {
      const end = toSuffixedValue(targetValueRaw)
      const startAttrRaw = el.getAttribute(key) || `0${end.suffix}`
      if (startAttrRaw === targetValueRaw) {
        el.setAttribute(key, targetValueRaw)
        return
      }
      const start = toSuffixedValue(startAttrRaw)
      if (start.suffix !== end.suffix) {
        throw new Error(
          `Cannot animate attribute "${key}" from "${startAttrRaw}" to "${targetValueRaw}" because they have different suffixes: "${start.suffix}" and "${end.suffix}".`,
        )
      }
      cancelAnimation()
      let startTime = 0
      let endTime = 0
      const updateAttribute = () => {
        const now = performance.now()
        let isFinished = now >= endTime
        let revisedValue = 0
        if (isFinished) {
          revisedValue = end.value
          const shouldLoop = mods.has('loop')
          const shouldPingPong = mods.has('pingpong')
          if (shouldLoop || shouldPingPong) {
            startTime = now
            endTime = now + duration
            if (shouldPingPong) {
              const temp = start.value
              start.value = end.value
              end.value = temp
            }
            revisedValue = start.value
            isFinished = false
          }
        } else {
          const baseT = inverseLerp(startTime, endTime, now)
          const easedT = easing(baseT)
          revisedValue = lerp(start.value, end.value, easedT)
        }
        el.setAttribute(key, `${revisedValue}${end.suffix}`)
        if (isFinished) cancelAnimation()
        else {
          animId = requestAnimationFrame(updateAttribute)
        }
      }
      setTimeout(() => {
        startTime = performance.now()
        endTime = startTime + duration
        animId = requestAnimationFrame(updateAttribute)
      }, delay)
    }
    if (!key) {
      return effect(() => {
        const binds = rx() as Record<string, string>
        for (const [key, val] of Object.entries(binds)) {
          startAttributeAnimation(key, val)
        }
      })
    }
    return effect(() => {
      const value = rx()
      startAttributeAnimation(key, `${value}`)
    })
  },
})

type SuffixedValue = {
  value: number
  suffix: string
}

const toSuffixedValue = (value: string): SuffixedValue => {
  const match = value.match(/^(-?\d*\.?\d+)([a-z%]*)$/i)
  if (match) {
    return {
      value: Number.parseFloat(match[1]),
      suffix: match[2] || '',
    }
  }
  throw new Error(`Invalid suffixed value: ${value}`)
}

const { sqrt, sin, cos, PI } = Math

type EasingFunction = (t: number) => number

const Easing: Record<string, EasingFunction> = {
  // No easing, no acceleration
  linear: (t: number) => t,

  // Accelerates fast, then slows quickly towards end
  quadratic: (t: number) => t * (-(t * t) * t + 4 * t * t - 6 * t + 4),

  // Overshoots over 1 and then returns to 1 towards end.
  cubic: (t: number) => t * (4 * t * t - 9 * t + 6),

  // Overshoots over 1 multiple times - wiggles around 1.
  elastic: (t: number) =>
    t * (33 * t * t * t * t - 106 * t * t * t + 126 * t * t - 67 * t + 15),

  // Accelerating from zero velocity
  inquad: (t: number) => t * t,

  // Decelerating to zero velocity
  outquad: (t: number) => t * (2 - t),

  // Acceleration until halfway, then deceleration
  inoutquad: (t: number) => (t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t),

  // Accelerating from zero velocity
  incubic: (t: number) => t * t * t,

  // Decelerating to zero velocity
  outcubic: (t: number) => --t * t * t + 1,

  // Acceleration until halfway, then deceleration
  inoutcubic: (t: number) =>
    t < 0.5 ? 4 * t * t * t : (t - 1) * (2 * t - 2) * (2 * t - 2) + 1,

  // Accelerating from zero velocity
  inquart: (t: number) => t * t * t * t,

  // Decelerating to zero velocity
  outquart: (t: number) => 1 - --t * t * t * t,

  // Acceleration until halfway, then deceleration
  inoutquart: (t: number) =>
    t < 0.5 ? 8 * t * t * t * t : 1 - 8 * --t * t * t * t,

  // Accelerating from zero velocity
  inquint: (t: number) => t * t * t * t * t,

  // Decelerating to zero velocity
  outquint: (t: number) => 1 + --t * t * t * t * t,

  // Acceleration until halfway, then deceleration
  inoutquint: (t: number) =>
    t < 0.5 ? 16 * t * t * t * t * t : 1 + 16 * --t * t * t * t * t,

  // Accelerating from zero velocity
  insine: (t: number) => -cos(t * (PI / 2)) + 1,

  // Decelerating to zero velocity
  outsine: (t: number) => sin(t * (PI / 2)),

  // Accelerating until halfway, then decelerating
  inoutsine: (t: number) => -(cos(PI * t) - 1) / 2,

  // Exponential accelerating from zero velocity
  inexpo: (t: number) => 2 ** (10 * (t - 1)),

  // Exponential decelerating to zero velocity
  outexpo: (t: number) => -(2 ** (-10 * t)) + 1,

  // Exponential accelerating until halfway, then decelerating
  inoutexpo: (t: number) => {
    t /= 0.5
    if (t < 1) return 2 ** (10 * (t - 1)) / 2
    t--
    return (-(2 ** (-10 * t)) + 2) / 2
  },

  // Circular accelerating from zero velocity
  incirc: (t: number) => -sqrt(1 - t * t) + 1,

  // Circular decelerating to zero velocity Moves VERY fast at the beginning and
  // then quickly slows down in the middle. This tween can actually be used
  // in continuous transitions where target value changes all the time,
  // because of the very quick start, it hides the jitter between target value changes
  outcirc: (t: number) => sqrt(1 - (t = t - 1) * t),

  // Circular acceleration until halfway, then deceleration
  inoutcirc: (t: number) => {
    t /= 0.5
    if (t < 1) return -(sqrt(1 - t * t) - 1) / 2
    t -= 2
    return (sqrt(1 - t * t) + 1) / 2
  },

  inelastic: (t: number) => {
    const c4 = (2 * PI) / 3
    return t === 0
      ? 0
      : t === 1
        ? 1
        : -(2 ** (10 * (t - 1))) * sin((t - 1.1) * c4)
  },

  outelastic: (t: number) => {
    const c4 = (2 * PI) / 3
    return t === 0 ? 0 : t === 1 ? 1 : 2 ** (-10 * t) * sin((t - 0.1) * c4) + 1
  },

  inoutelastic: (t: number) => {
    const c5 = (2 * PI) / 4.5
    return t === 0
      ? 0
      : t === 1
        ? 1
        : t < 0.5
          ? (-(2 ** (20 * t - 10)) * sin((20 * t - 11.125) * c5)) / 2
          : (2 ** (-20 * t + 10) * sin((20 * t - 11.125) * c5)) / 2 + 1
  },

  inback: (t: number) => {
    const s = 1.70158
    return t * t * ((s + 1) * t - s)
  },
  outback: (t: number) => {
    const s = 1.70158
    return (t = t - 1) * t * ((s + 1) * t + s) + 1
  },
  inoutback: (t: number) => {
    const s = 1.70158 * 1.525
    t /= 0.5
    if (t < 1) return (t * t * ((s + 1) * t - s)) / 2
    t -= 2
    return (t * t * ((s + 1) * t + s) + 2) / 2
  },

  inbounce: (t: number) => 1 - Easing.outBounce(1 - t),
  outbounce: (t: number) => {
    if (t < 1 / 2.75) {
      return 7.5625 * t * t
    }
    if (t < 2 / 2.75) {
      t -= 1.5 / 2.75
      return 7.5625 * t * t + 0.75
    }
    if (t < 2.5 / 2.75) {
      t -= 2.25 / 2.75
      return 7.5625 * t * t + 0.9375
    }
    t -= 2.625 / 2.75
    return 7.5625 * t * t + 0.984375
  },

  inoutbounce: (t: number) => {
    if (t < 0.5) return Easing.inBounce(t * 2) / 2
    return Easing.outBounce(t * 2 - 1) / 2 + 0.5
  },

  ingolden: (t: number) => t ** 1.834057,
  outgolden: (t: number) => 1 - (1 - t) ** 1.834057,
  inoutgolden: (t: number) => {
    if (t < 0.5) return Easing.inGolden(t * 2) / 2
    return Easing.outGolden(t * 2 - 1) / 2 + 0.5
  },
}

// Icon: mdi-message-alert
// Slug: Adds custom validity to an element.
// Description: Allows you to add custom validity to an element using an expression.

import { attribute } from '@engine'
import { effect } from '@engine/signals'

attribute({
  name: 'custom-validity',
  requirement: {
    key: 'denied',
    value: 'must',
  },
  returnsValue: true,
  apply({ el, rx, error }) {
    if (
      !(
        el instanceof HTMLInputElement ||
        el instanceof HTMLSelectElement ||
        el instanceof HTMLTextAreaElement
      )
    ) {
      throw error('CustomValidityInvalidElement', {
        element: { tag: el.tagName },
      })
    }
    return effect(() => {
      const result = rx() as string
      if (typeof result !== 'string') {
        throw error('CustomValidityInvalidExpression', {
          expression: { value: result },
        })
      }
      el.setCustomValidity(result)
    })
  },
})

// Icon: material-symbols:media-link-outline
// Slug: Matches a media query and stores the result in a signal.
// Description: Sets a signal to whether a media query currently matches, keeps it in sync on change, and resets the signal on cleanup.

import { attribute } from '@engine'
import { mergePaths } from '@engine/signals'
import { modifyCasing } from '@utils/text'

attribute({
  name: 'match-media',
  requirement: {
    key: 'must',
    value: 'must',
  },
  apply({ key, mods, value }) {
    const signalName = modifyCasing(key, mods)
    let query = value?.trim() ?? ''
    if (/^(["'`]).*\1$/.test(query)) {
      query = query.slice(1, -1).trim()
    }
    if (!/[()]/.test(query)) query = `(${query})`

    let mql: MediaQueryList | undefined
    try {
      mql = window.matchMedia(query)
    } catch {}

    const listener = (event: MediaQueryListEvent) =>
      mergePaths([[signalName, event.matches]])

    mergePaths([[signalName, mql?.matches ?? false]])
    mql?.addEventListener('change', listener)

    return () => {
      mql?.removeEventListener('change', listener)
      mergePaths([[signalName, null]])
    }
  },
})

// Icon: material-symbols:animated-images-outline
// Slug: Runs an expression on every animation frame.
// Description: Runs an expression on every `requestAnimationFrame` event.

import { attribute } from '@engine'
import { beginBatch, endBatch } from '@engine/signals'
import { modifyTiming } from '@utils/timing'
import { modifyViewTransition } from '@utils/view-transitions'

attribute({
  name: 'on-raf',
  requirement: {
    key: 'denied',
    value: 'must',
  },
  apply({ mods, rx }) {
    let callback = () => {
      beginBatch()
      rx()
      endBatch()
    }
    callback = modifyViewTransition(callback, mods)
    callback = modifyTiming(callback, mods)
    let rafId: number | undefined
    const raf = () => {
      callback()
      rafId = requestAnimationFrame(raf)
    }
    rafId = requestAnimationFrame(raf)
    return () => {
      if (rafId) {
        cancelAnimationFrame(rafId)
      }
    }
  },
})

// Icon: material-symbols:resize-rounded
// Slug: Runs an expression on element resize.
// Description: Runs an expression whenever an element’s dimensions change.

import { attribute } from '@engine'
import { beginBatch, endBatch } from '@engine/signals'
import { modifyTiming } from '@utils/timing'
import { modifyViewTransition } from '@utils/view-transitions'

attribute({
  name: 'on-resize',
  requirement: {
    key: 'denied',
    value: 'must',
  },
  apply({ el, mods, rx }) {
    let callback = () => {
      beginBatch()
      rx()
      endBatch()
    }
    callback = modifyViewTransition(callback, mods)
    callback = modifyTiming(callback, mods)
    let resizeObserver: ResizeObserver | null = new ResizeObserver(() => {
      callback()
    })
    resizeObserver.observe(el)
    return () => {
      if (resizeObserver) {
        resizeObserver.disconnect()
        resizeObserver = null
      }
    }
  },
})

// Icon: material-symbols:keep-outline-rounded
// Slug: Persists signals in local storage.
// Description: Persists signals in local storage.

import { attribute } from '@engine'
import { effect, filtered, mergePatch } from '@engine/signals'
import type { SignalFilterOptions } from '@engine/types'

attribute({
  name: 'persist',
  returnsValue: true,
  apply({ key, mods, rx }) {
    const storageKey = key || 'datastar'
    const storage = mods.has('session') ? sessionStorage : localStorage

    // Load from storage after current execution cycle
    const fromStorage = storage[storageKey]
    if (fromStorage) {
      try {
        const parsed = JSON.parse(fromStorage)
        mergePatch(parsed)
      } catch (e) {
        console.error('Failed to parse persisted data:', e)
      }
    }

    return effect(() => {
      const toStore = filtered(rx?.() as SignalFilterOptions)
      const json = JSON.stringify(toStore)
      storage[storageKey] = json
    })
  },
})

// Icon: material-symbols:link-rounded
// Slug: Syncs query string params with signal values.
// Description: Syncs query string params to signal values on page load, and syncs signal values to query string params on change.

import { attribute } from '@engine'
import { effect, filtered, mergePaths } from '@engine/signals'
import type { Paths, SignalFilterOptions } from '@engine/types'
import { isEmpty } from '@utils/paths'

attribute({
  name: 'query-string',
  requirement: {
    key: 'denied',
  },
  returnsValue: true,
  apply({ mods, rx }) {
    const historySupport = mods.has('history')
    let isPopsate = false

    const getUrlParams = () => new URLSearchParams(window.location.search)
    const filteredSignals = () => filtered(rx?.() as SignalFilterOptions)

    const queryStringToSignals = () => {
      const urlParams = getUrlParams()
      const masked = filteredSignals()
      const updates: Paths = []

      // Helper to get all paths from masked object
      const getPaths = (obj: Record<string, any>, prefix = ''): string[] => {
        const paths: string[] = []
        for (const key in obj) {
          const path = prefix ? `${prefix}.${key}` : key
          const val = obj[key]
          if (val && typeof val === 'object' && !(val instanceof HTMLElement)) {
            paths.push(...getPaths(val, path))
          } else {
            paths.push(path)
          }
        }
        return paths
      }

      const matchingPaths = getPaths(masked)
      for (const path of matchingPaths) {
        const value = urlParams.get(path)
        if (value !== null) {
          // Try to parse as number, boolean, or keep as string
          let parsedValue: any = value
          if (value === 'true') {
            parsedValue = true
          } else if (value === 'false') {
            parsedValue = false
          } else if (!Number.isNaN(+value) && value !== '') {
            parsedValue = +value
          }
          updates.push([path, parsedValue])
        }
      }

      if (!isEmpty(updates)) {
        mergePaths(updates)
      }
    }

    // Load initial values from URL
    queryStringToSignals()

    // Handle browser back/forward navigation
    const popstateHandler = () => {
      isPopsate = true
      queryStringToSignals()
      isPopsate = false
    }

    if (historySupport) {
      window.addEventListener('popstate', popstateHandler)
    }

    const effectCleanup = effect(() => {
      // Don't update URL during popstate events
      if (isPopsate) {
        return
      }

      const urlParams = new URLSearchParams()
      const origUrlString = getUrlParams().toString()

      const setURLParamFromValue = (obj: Record<string, any>, path: string) => {
        for (const key in obj) {
          const val = obj[key]
          const newPath = path.length ? `${path}.${key}` : key
          if (val instanceof HTMLElement) continue

          if (typeof val === 'object') {
            setURLParamFromValue(val, newPath)
          } else {
            if (!mods.has('filter') || val) {
              urlParams.set(newPath, `${val}`)
            }
          }
        }
      }
      setURLParamFromValue(filteredSignals(), '')

      const newUrlString = urlParams.toString()
      if (newUrlString !== origUrlString) {
        const newUrl = newUrlString
          ? `?${newUrlString}`
          : window.location.pathname
        if (historySupport) {
          window.history.pushState({}, '', newUrl)
        } else {
          window.history.replaceState({}, '', newUrl)
        }
      }
    })

    // Return cleanup function
    return () => {
      if (historySupport) {
        window.removeEventListener('popstate', popstateHandler)
      }
      effectCleanup()
    }
  },
})

// Icon: material-symbols:swap-calls
// Slug: Replaces the URL in the browser.
// Description: Replaces the URL in the browser without reloading the page.

import { attribute } from '@engine'
import { effect } from '@engine/signals'

attribute({
  name: 'replace-url',
  requirement: {
    key: 'denied',
    value: 'must',
  },
  returnsValue: true,
  apply({ rx }) {
    return effect(() => {
      const url = rx() as string
      const baseUrl = window.location.href
      const fullUrl = new URL(url, baseUrl).toString()
      window.history.replaceState({}, '', fullUrl)
    })
  },
})

// Icon: material-symbols:masked-transitions
// Slug: Sets `view-transition-name` styles.
// Description: Sets the `view-transition-name` style attribute explicitly.

import { attribute } from '@engine'
import { effect } from '@engine/signals'
import { supportsViewTransitions } from '@utils/view-transitions'

attribute({
  name: 'view-transition',
  requirement: {
    key: 'denied',
    value: 'must',
  },
  returnsValue: true,
  apply({ el, rx }) {
    if (!supportsViewTransitions) {
      console.warn('Browser does not support view transitions')
      return
    }
    return effect(() => {
      const name = rx() as string
      if (name) {
        el.style.viewTransitionName = name
      }
    })
  },
})
